# ESLint Configuration

ESLint flat config exports an array of configuration objects from `eslint.config.js` (or `.mjs`/`.cjs`). Each object can target specific files and define rules, plugins, globals, and parser options.

## Initialize a New Project

```bash
# Guided setup — creates eslint.config.mjs with prompts
npm init @eslint/config@latest

# Manual setup
npm install --save-dev eslint @eslint/js
```

## Minimal Config

```javascript
// eslint.config.mjs
import js from "@eslint/js";

export default [
  js.configs.recommended,
];
```

## Full Config Structure

```javascript
// eslint.config.mjs
import js from "@eslint/js";
import globals from "globals";

export default [
  // Recommended rules from @eslint/js
  js.configs.recommended,

  // Global ignores (must be standalone object with ONLY ignores key)
  {
    ignores: ["dist/", "build/", "node_modules/", "coverage/", "**/*.min.js"],
  },

  // Main source config
  {
    files: ["src/**/*.{js,mjs,cjs}"],
    languageOptions: {
      ecmaVersion: 2024,
      sourceType: "module",
      globals: {
        ...globals.browser,
        ...globals.node,
      },
    },
    rules: {
      "no-unused-vars": ["error", { argsIgnorePattern: "^_" }],
      "no-console": "warn",
      "prefer-const": "error",
      eqeqeq: ["error", "always"],
    },
  },

  // Test file overrides
  {
    files: ["**/*.test.{js,ts}", "**/*.spec.{js,ts}"],
    languageOptions: {
      globals: {
        ...globals.jest,
      },
    },
    rules: {
      "no-unused-expressions": "off",
    },
  },
];
```

## TypeScript Configuration

```javascript
// eslint.config.mjs
import js from "@eslint/js";
import tseslint from "typescript-eslint";
import globals from "globals";

export default tseslint.config(
  js.configs.recommended,
  ...tseslint.configs.recommended,
  {
    ignores: ["dist/", "node_modules/"],
  },
  {
    files: ["src/**/*.ts"],
    languageOptions: {
      globals: { ...globals.node },
      parserOptions: {
        projectService: true,
        tsconfigRootDir: import.meta.dirname,
      },
    },
    rules: {
      "@typescript-eslint/no-unused-vars": ["error", { argsIgnorePattern: "^_" }],
      "@typescript-eslint/no-explicit-any": "warn",
    },
  },
);
```

## React Configuration

```javascript
// eslint.config.mjs
import js from "@eslint/js";
import react from "eslint-plugin-react";
import reactHooks from "eslint-plugin-react-hooks";
import globals from "globals";

export default [
  js.configs.recommended,
  {
    files: ["src/**/*.{jsx,tsx}"],
    plugins: {
      react,
      "react-hooks": reactHooks,
    },
    languageOptions: {
      globals: { ...globals.browser },
      parserOptions: {
        ecmaFeatures: { jsx: true },
      },
    },
    rules: {
      ...reactHooks.configs.recommended.rules,
      "react/react-in-jsx-scope": "off",
      "react/prop-types": "off",
    },
    settings: {
      react: { version: "detect" },
    },
  },
];
```

## Ignores

Global ignores must be a standalone config object with only the `ignores` key:

```javascript
export default [
  // Global ignores — applied to all files
  { ignores: ["dist/", "build/", "*.config.js"] },

  // Per-config ignores — only for matched files
  {
    files: ["src/**/*.js"],
    ignores: ["src/generated/**"],
    rules: { /* ... */ },
  },
];
```

## Language Options

| Option | Values | Default |
|--------|--------|----------|
| `ecmaVersion` | `2015`-`2025`, `"latest"` | `"latest"` |
| `sourceType` | `"module"`, `"commonjs"`, `"script"` | `"module"` for `.mjs`, `"commonjs"` for `.cjs` |
| `globals` | Object from `globals` package | `{}` |
| `parser` | Custom parser object | espree |
| `parserOptions` | Parser-specific options | `{}` |

## Using defineConfig Helper

```javascript
import { defineConfig } from "eslint/config";
import js from "@eslint/js";

export default defineConfig([
  { extends: [js.configs.recommended] },
  {
    files: ["src/**/*.js"],
    rules: { "no-console": "warn" },
  },
]);
```

## Verify Config

```bash
# Print resolved config for a specific file
npx eslint --print-config src/index.js

# Interactive config inspector
npx eslint --inspect-config
```
